"""
Standalone patch — writes mkt-context for Psalms 71-74 directly.
Run: python3 scripts/zc-context-psalms-71-74-patch.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSA_CONTEXT = {
  "71": {
    "1": "<p>Psalm 71 is an anonymous psalm widely understood to be an old man's prayer based on vv. 9, 18 ('when old age comes,' 'in old age and gray hair'). It is heavily intertextual, weaving together language from Ps 22 (birth-covenant), Ps 31 (rock of refuge), and Ps 22's pattern of lament to praise. 'In you, O LORD, I take refuge; let me never be put to shame' — the opening line quotes Ps 31:1 nearly verbatim, establishing the psalm as a consciously composed meditation on earlier psalmic tradition. The psalmist is one who has been formed by the liturgical texts of the community and prays out of that formation.</p>",
    "2": "<p>'In your righteousness deliver me and rescue me; incline your ear to me and save me' — the appeal to YHWH's covenant righteousness as the basis for deliverance. YHWH's tsedaqah (righteousness) was not merely a moral category but a relational-covenantal one: the committed faithfulness to his people that constitutes his covenant character. To appeal to YHWH's righteousness is to appeal to what YHWH owes to himself and to the covenant relationship. 'Incline your ear' is the posture of the attentive patron bending toward the client in court.</p>",
    "3": "<p>'Be for me a sheltering rock, a place I can always come to; you have commanded my salvation, for you are my rock and my fortress' — the repeated rock-and-fortress metaphor throughout Book II (Ps 42-72). The specific phrase 'a place I can always come to' implies the psalmist's ongoing return to this refuge — not a one-time rescue but a habitual shelter sought throughout life. 'You have commanded my salvation' is a striking claim: YHWH has decreed the psalmist's salvation as a sovereign act.</p>",
    "4": "<p>'Rescue me, O my God, from the hand of the wicked, from the grip of the unjust and cruel' — 'the unjust and cruel' are those who use power without covenant restraint. The 'hand' and 'grip' of the wicked describe the social mechanism of oppression: being physically or legally controlled by those with power. Ancient Israel's legal system gave significant power to creditors, landowners, and patrons; without YHWH's intervention, the powerless person had no recourse against those who could grip them.</p>",
    "5": "<p>'For you, O Lord GOD, are my hope, my trust from my earliest years' — 'Lord GOD' (Adonai Yhwh) is the doubled divine title that appears in formal covenant address and prophetic literature (Ezek uses it frequently; Gen 15:2, 8: Abraham's prayer). 'My hope from my earliest years' — the lifelong orientation of trust toward YHWH from youth: the psalmist's entire existence has been structured by covenant dependence, not as a late resort but as the original condition of life.</p>",
    "6": "<p>'I have depended on you from before I was born; you drew me safely out of my mother's womb. My praise is forever your own' — the birth-covenant language echoes Ps 22:9-10 and Isa 49:1 (the Servant formed in the womb). Prenatal dependence on YHWH is the most extreme statement of total covenant reliance: even before consciousness or choice, the psalmist's existence was sustained by divine care. YHWH present at the physical moment of birth as active helper established the covenant relationship before any human decision was possible.</p>",
    "7": "<p>'I have been like an astonishing sign to many, but you are my strong shelter' — 'an astonishing sign (mofet, wonder/portent) to many' — the psalmist's life has been visible to others as a remarkable thing: perhaps repeated rescues, long life, or survival through adversity that made others take notice. Mofet is often used for miraculous signs given by prophets (Exod 7:9; Deut 13:1-3; Isa 8:18: 'I and the children the LORD has given me are signs and wonders in Israel'). The psalmist's survival is itself a visible testimony to YHWH's sustaining power.</p>",
    "8": "<p>'My mouth is full of your praise and your glory all the day long' — praise as the continuous occupation of the psalmist's mouth: the expression of thankfulness that cannot wait for special occasions but fills daily speech. 'Glory' (tipharetecha, your splendor/beauty) is YHWH's covenant glory as the content of constant proclamation. The mouth filled with praise replaces the mouth that might be filled with complaint or fear — the discipline of praise as covenant orientation even amid the crisis described in vv. 9-12.</p>",
    "9": "<p>'Do not reject me when old age comes; do not abandon me when my strength gives out' — the distinctive petition of this psalm: the fear specific to old age. In ancient Israel, when a person's physical strength declined, their social value in the patron-client system could decrease proportionally. The fear is that YHWH might relate to the psalmist as human patrons do — withdrawing as the client becomes unable to contribute. The petition asserts that the divine patron does not operate on the social contract of mutual benefit.</p>",
    "10": "<p>'For my enemies speak about me; those who watch for my life conspire together' — the enemies taking advantage of the elderly psalmist's vulnerability. Those who 'watch for my life' are the scouts who monitor the target, waiting for the moment to strike. Conspiracy against the vulnerable elder follows the pattern of Ps 31 and 41 — the council of enemies working in concert against the isolated covenant sufferer. Elderly or infirm people in ancient Near Eastern societies were particularly vulnerable to such exploitation.</p>",
    "11": "<p>'They say, God has abandoned him; run him down and take him, for there is no one to rescue him' — the 'God has abandoned him' taunt is the enemies' theological argument: the psalmist's vulnerability in old age is read as evidence of divine abandonment. The same logic appears in Ps 22:8; 41:11 — suffering is interpreted as divine withdrawal. 'There is no one to rescue him' — the patronage network has collapsed; no human patron remains. This makes YHWH the last and only recourse — which is precisely where the psalmist wants to press the petition.</p>",
    "12": "<p>'O God, do not be far from me; O my God, come quickly to my aid' — the spatial urgency: YHWH's distance (or perceived distance) is the crisis. The 'come quickly' has specific military resonance: the reinforcements arriving before the position falls. Ps 22:19 uses the same language. The elderly psalmist's sense of being surrounded and the urgency of the petition mirror the Passion Psalm's structure.</p>",
    "13": "<p>'Let those who attack my life be put to shame and consumed; let those who seek my harm be wrapped in reproach and disgrace' — the imprecatory petition: the reversal of shame onto those who sought to inflict it. In the honor-shame world, the prayer for enemies to be 'put to shame' was a legal appeal to the divine judge to render a verdict against the accusers. The language of total social humiliation returns upon those who sought it for the psalmist.</p>",
    "14": "<p>'But I will hope continually and will praise you more and more' — the deliberate contrast with v. 13's petition against enemies: the psalmist's own path is not revenge or bitterness but escalating hope and praise. 'More and more' (I will add to all your praises) — praise as an accumulating practice: each act of praise adds to the corpus of the psalmist's testimony. The aging psalmist does not diminish in covenant engagement but amplifies it.</p>",
    "15": "<p>'My mouth will proclaim your righteousness and your saving acts all the day long, for I cannot count their number' — the uncountable nature of YHWH's saving acts: the psalmist's lifetime of experience with divine rescue has produced more incidents than can be enumerated. The accumulation of YHWH's faithfulness through the years exceeds the capacity of memory and speech to catalog. The old man's prayer is precisely that he has too many rescues to list, not too few.</p>",
    "16": "<p>'I will come in the strength of the Lord GOD; I will declare your righteousness — yours and no one else's' — 'in the strength of the Lord GOD' (bigvurot Adonai Yhwh) — YHWH's power is the basis for the psalmist's approach to the sanctuary. The double divine title signals formal covenant address. 'Yours and no one else's' (tsidqatecha levadecha, your righteousness alone) — the emphatic exclusivity: YHWH's righteousness is the only righteousness that has sustained the psalmist, not the psalmist's own merit or human assistance.</p>",
    "17": "<p>'O God, you have taught me from my youth, and to this day I am still declaring your wonderful deeds' — the intergenerational covenant education: YHWH as the divine teacher from youth (cf. Ps 25:4-5, 8-9; Prov 22:6). The psalmist's lifelong testimony is the fruit of this lifelong divine instruction. The connection between being taught and being a teacher/testifier is direct: YHWH's formation produces the psalmist's proclamation.</p>",
    "18": "<p>'And even now in old age, with gray hair, O God, do not forsake me until I have proclaimed your strength to this generation' — the explicit generational mission: the elderly psalmist wants to live long enough to transmit YHWH's covenant acts to the next generation. The Deuteronomic transmission command (Deut 6:20-25; Ps 78:4-7) required the parents' generation to pass on YHWH's story. The survival of the old person's proclamation task is the stated reason for continued life.</p>",
    "19": "<p>'Your righteousness, O God, reaches the high heavens; you who have done such great things, O God — who is like you?' — the incomparability formula (mi kamocha, who is like you?) is the standard rhetorical form for asserting YHWH's uniqueness among the gods (Exod 15:11; Ps 35:10; 86:8; 89:6, 8; Isa 40:18, 25; 46:5). YHWH's righteousness 'reaching the high heavens' establishes the cosmic scope of a moral attribute that other ANE religions attached to physical power or territory — YHWH's righteousness is as expansive as the heavens themselves.</p>",
    "20": "<p>'You who have made me experience many bitter troubles will revive me again; from the depths of the earth you will bring me up again' — the resurrection imagery: YHWH who sent the psalmist down to the 'depths of the earth' (Sheol) will bring him back up. This is not necessarily literal resurrection but the pattern of covenant rescue from near-death experiences: the one who went down comes back up. Yet the imagery reaches beyond the immediate situation to the pattern of divine life-from-death that early Judaism read as pointing to bodily resurrection (cf. Ezek 37's valley of dry bones).</p>",
    "21": "<p>'You will increase my honor and surround me with comfort' — the reversal of the shame-cycle: the honor that the enemies sought to extinguish YHWH will 'increase.' Surrounded by comfort inverts the image of being surrounded by enemies. The same spatial encirclement that described threat (enemies conspiring, lying in wait) now describes safety (comfort encircling the psalmist).</p>",
    "22": "<p>'I will praise you with the lyre for your faithfulness, O my God; I will sing to you with the harp, O Holy One of Israel' — the musical instruments of the temple worship: lyre and harp were the primary instruments of the Levitical singers (1 Chr 15:16; 25:1-6; Ps 33:2; 150:3). 'Holy One of Israel' (qedosh yisrael) is the distinctive prophetic title for YHWH in Isaiah (appearing 26 times in Isaiah alone): the divine holiness that makes YHWH utterly unlike everything else. The psalmist's use of this Isaianic title suggests the influence of prophetic tradition on late psalmic composition.</p>",
    "23": "<p>'My lips will shout for joy when I sing praises to you; and my soul, which you have redeemed, will also rejoice' — 'my soul which you have redeemed' — pada (redeem) is the ransom/release vocabulary of the covenant: YHWH paying the price to release the bound or enslaved (Deut 7:8: 'The LORD redeemed you from slavery'). The psalmist's soul has been specifically and personally redeemed by YHWH — an act of expensive covenant love, not merely general providential care.</p>",
    "24": "<p>'And my tongue will speak of your righteous deeds all day long, for those who sought to harm me have been put to shame and disgraced' — the psalm closes with the same elements as it opened with (mouth, praise, shame of enemies) but now in the confident future tense or as completed action. The enemies' shame is the concluding vindication: the taunt of vv. 10-11 ('God has abandoned him') has been answered by the reversal of their own position. The psalmist's ongoing speech throughout the day is both personal gratitude and public testimony that refutes the enemies' diagnosis.</p>"
  },
  "72": {
    "1": "<p>Psalm 72 bears the superscription 'A Psalm of Solomon' — either composed by Solomon or for him. It closes Book II of the Psalter (Ps 42-72) and v. 20 ('the prayers of David, the son of Jesse, are ended') indicates it is the editorial closing of a Davidic collection within Book II. The Psalm is a royal prayer for the king's justice, and its language escalates from possible historical prayer to clearly eschatological vision. 'O God, give the king your justice, and your righteousness to the king's son' — the petition that the king would exercise YHWH's own qualities of justice and righteousness in governance. These are the primary attributes of divine governance (Ps 89:14: 'Righteousness and justice are the foundation of your throne').</p>",
    "2": "<p>'May he judge your people with righteousness and your poor with justice' — the two primary objects of royal justice: 'your people' in general and 'your poor' specifically. In ancient Israelite royal ideology (and throughout the ANE), the king's primary obligation was the protection of the poor, widow, and orphan from exploitation by the powerful. Hammurabi's law code opens with the claim that Marduk commissioned him to ensure the strong do not oppress the weak. Ps 72:2-4 and 12-14 describe the covenant king's essential function: protecting those who cannot protect themselves.</p>",
    "3": "<p>'May the mountains bring peace to the people, and the hills, through righteousness' — the cosmic dimension of righteous governance: right rule by the king produces agricultural fertility and peace in the natural order. The mountains bringing shalom (peace/wholeness) is the covenant blessing of Lev 26:4-6 expressed in royal theology. Just kingship is inseparable from natural abundance — the land itself responds to covenant faithfulness.</p>",
    "4": "<p>'May he defend the cause of the poor of the people, give deliverance to the children of the needy, and crush the oppressor' — the three-fold royal justice mandate: defending, delivering, crushing. 'The children of the needy' (benei evyon, children of the destitute) — the most vulnerable of the vulnerable: the children of those at the absolute bottom of the social scale. These three acts define the king's vocation: not conquest of foreign nations but internal justice, protecting the poor against the powerful.</p>",
    "5": "<p>'May they fear you as long as the sun and moon endure, through all generations' — the eschatological extension of the prayer: not just for the present king's reign but 'through all generations' while sun and moon exist. The sun and moon as measures of temporal duration are the cosmic markers of permanence (cf. Ps 89:36-37: the Davidic throne established 'as long as the sun endures ... like the moon established forever'). The prayer expands from historical kingship to the eternal kingdom that all Davidic kings pointed toward.</p>",
    "6": "<p>'May he be like rain falling on newly mown grass, like showers that water the earth' — the agricultural metaphor of the king's beneficent presence. Rain on newly mown grass was the timing of the spring rains in Israel's agricultural calendar: the early rains after the harvest prepared the ground for the next cycle. The king's just rule is like the seasonal rain that makes agricultural life possible — without it, everything withers; with it, all grows. The metaphor identifies the king's justice with the natural order of fertility.</p>",
    "7": "<p>'In his days may the righteous flourish, and peace abound, until the moon is no more' — 'the righteous will flourish' — the correspondence between righteous governance and the flourishing of the righteous: the just king creates conditions under which covenant-faithful people can thrive. 'Until the moon is no more' — beyond the limits of the cosmic order itself, reaching eschatological finality. The prayer's temporal horizon has expanded to encompass the end of the present cosmos.</p>",
    "8": "<p>'May he have dominion from sea to sea, from the River to the ends of the earth' — the universal dominion formula. 'From sea to sea' and 'from the River (Euphrates) to the ends of the earth' is the maximum geographical extent possible in the ancient Near Eastern conceptual world. This is the Abrahamic promise of universal blessing (Gen 12:3; 22:17-18) applied to the Davidic king, and it is the same language used in Zech 9:10 for the coming king who would 'speak peace to the nations' — the messianic king on a donkey.</p>",
    "9": "<p>'May desert peoples bow before him, and his enemies lick the dust' — the 'lick the dust' was the extreme submission gesture in ancient Near Eastern protocol: the prostrated vassal's mouth at ground level before the king. ANE royal inscriptions and art regularly depicted conquered peoples in this posture. The 'desert peoples' and enemies bowing evoke universal submission — not just the known nations but even those on the margins of the known world.</p>",
    "10": "<p>'May the kings of Tarshish and the coastlands bring tribute; may the kings of Sheba and Seba offer gifts' — specific named locations representing the known world's extremities. Tarshish was in the far west (likely Spain or Sardinia — the most distant point of the ancient Phoenician trading world; cf. Jonah's attempt to flee there). Sheba was in the far south (Arabia or East Africa — the source of spice and gold; 1 Kgs 10: the Queen of Sheba's visit to Solomon). The four directions of the known world bring tribute to the ideal king.</p>",
    "11": "<p>'Yes, may all kings bow down before him; may all nations serve him' — the universal scope: every political sovereign and every ethnic group. This is the eschatological vision of Ps 2:8 and Isa 49:23 combined. In the NT, this vision is applied to Christ — the King before whom every knee will bow (Phil 2:10-11: 'at the name of Jesus every knee shall bow ... every tongue confess that Jesus Christ is Lord').</p>",
    "12": "<p>'For he delivers the needy when they cry for help, the poor and those who have no one to help them' — the 'for' grounds the universal submission of v. 11 in the king's care for the poor: the nations submit because this king is genuinely just. Unlike other ancient conquerors whose power was built on exploiting the weak, this king's authority rests on protecting the powerless. The king's greatness is measured not by tribute extracted but by the needy delivered.</p>",
    "13": "<p>'He has compassion on the weak and the needy, and saves the lives of the poor' — 'compassion' is the Hebrew term for the tender concern that protects rather than exploits. 'Saves the lives of the poor' — the most direct intervention: preserving the very existence of those who would otherwise perish. In ancient law, the death of a poor person who could not pay debts was not necessarily the state's concern; the ideal king makes it his personal business.</p>",
    "14": "<p>'He redeems their life from oppression and violence, and their blood is precious in his eyes' — 'their blood is precious in his eyes' is the king's counter-logic to oppression: in a world where the powerful treated the poor as disposable, this king values the life of the powerless as costly. The ransom/redemption vocabulary is the same used for YHWH redeeming Israel from Egypt. The king who redeems the poor images YHWH's own redemptive character.</p>",
    "15": "<p>'Long may he live! May gold from Sheba be given to him! May prayer be made for him continually and blessings pronounced on him all day long' — the coronation liturgy of prayer and blessing for the king. 'Gold from Sheba' was the most prestigious gold in the ancient world (cf. Job 28:16; Isa 60:6: Sheba's gold coming to Jerusalem in the eschatological pilgrimage). The subjects' ongoing prayer and blessing for the king is the people's liturgical support of the royal office.</p>",
    "16": "<p>'May grain be abundant throughout the land; may it wave on the mountaintops; may its yield be like Lebanon, and may the city bloom like the grass of the field' — the agricultural vision of the righteous king's reign: grain growing even on the mountaintops (normally too exposed for cultivation), yield as lush as the cedar forests of Lebanon (the most densely vegetated landscape in the ancient Near East). This is the reversal of the Deuteronomic curse (Deut 28:23: 'The sky over your head will be bronze, the ground beneath your feet iron') — the land expressing the covenant blessing of right rule.</p>",
    "17": "<p>'May his name endure forever; may it continue as long as the sun endures! May all peoples find blessing through him; may they call him blessed' — 'his name endure forever' echoes the Davidic covenant promise (2 Sam 7:13: 'I will establish the throne of his kingdom forever'). 'May all peoples find blessing through him' (veyitbarachu vo kol-goyim, all nations shall bless themselves in him) — the Abrahamic blessing formula of Gen 12:3 ('in you all families of the earth shall be blessed') now applied to the Davidic king. The king becomes the conduit of the Abrahamic promise to the nations.</p>",
    "18": "<p>'Blessed be the LORD, the God of Israel, who alone does wondrous things' — the doxology that begins the close of Book II. 'Who alone does wondrous things' — divine exclusivity in miracle-working: only YHWH, not the king, not any human patron, performs the genuinely marvelous acts. The doxology redirects the psalm's accumulated praise from the ideal king to the God who gives the king his authority and character.</p>",
    "19": "<p>'Blessed be his glorious name forever; may the whole earth be filled with his glory! Amen and Amen' — the double 'Amen and Amen' closes Book II (as Ps 41:13's 'Amen and Amen' closed Book I). The prayer that 'the whole earth be filled with his glory' echoes the seraphim's acclamation of Isa 6:3 ('the whole earth is full of his glory') and the prayer of Moses in Num 14:21 ('all the earth shall be filled with the glory of the LORD'). The Psalter's editorial design reaches toward this eschatological hope: the God of Israel glorified throughout all creation.</p>",
    "20": "<p>'The prayers of David, the son of Jesse, are ended' — the editorial colophon closing the Davidic collection within Book II. The statement is editorially significant: many psalms after Ps 72 bear Davidic superscriptions, so 'ended' refers to this collection specifically, not to all Davidic psalms in the Psalter. The colophon makes visible the editorial process behind the Psalter: collections of psalms were assembled and organized by editors who left markers of their work. 'David the son of Jesse' — the full genealogical identification emphasizes the historical particularity of the one from whom the royal tradition flows.</p>"
  },
  "73": {
    "1": "<p>Psalm 73 opens Book III of the Psalter (Ps 73-89) and is attributed to Asaph, the Levitical musician appointed by David (1 Chr 6:39; 15:17) who became the head of one of the three guilds of temple singers. Psalm 73 is one of the great wisdom-theodicy psalms of the OT, comparable to Job in its engagement with the problem of the wicked prospering. 'Truly God is good to Israel, to those who are pure in heart' — the psalm opens with the conclusion reached only after the crisis of vv. 2-16 and the resolution of v. 17. The opening statement is the post-sanctuary wisdom, not the naive assumption the psalmist held throughout. The psalm is structured as a retrospective: this is what I know now, having been through the crisis.</p>",
    "2": "<p>'But as for me, my feet nearly slipped; my steps almost gave way' — the psalmist's near-apostasy: the 'slipping' and 'almost giving way' are the metaphors of losing footing on the covenant path. The 'slippery ground' (v. 18) on which the wicked stand becomes the ground on which the psalmist himself nearly slipped — the crisis was interior, not external. The psalm admits that the observation of the wicked's prosperity nearly destroyed the psalmist's own covenant faith.</p>",
    "3": "<p>'For I was envious of the arrogant when I saw how the wicked prosper' — the theodicy problem stated plainly: seeing the wicked's visible, undeniable prosperity produces envy and the corresponding question about covenant justice. 'Arrogant' (holalim, boasters/fools) are those who live without reference to YHWH — the 'fool' (naval) of Ps 14:1 who says there is no God. The problem is not abstract but visceral: the psalmist saw the wicked prospering and found in this a specific challenge to the covenant premise that righteousness is rewarded.</p>",
    "4": "<p>'For they have no anguish in their death; their bodies are sleek and strong' — the specific evidence: the wicked die without suffering. 'Sleek and strong' (bari ulam, fat and healthy) — the well-fed, physically robust condition of the prosperous wicked is the visible sign of their ease. In the ancient world, physical robustness was a sign of divine favor; the wicked's gleaming health contradicts the expected covenant correlation between wickedness and physical decline.</p>",
    "5": "<p>'They are not in trouble like other people; they are not plagued like the rest of mankind' — the wicked's exemption from common human suffering: they do not share in the general troubles or in the plagues of humanity. This exemption from suffering is what makes their prosperity so theologically troubling: they lack not only punishment but even the normal burdens of human existence. They seem to operate under different rules.</p>",
    "6": "<p>'Therefore pride adorns them like a necklace; violence wraps them like a garment' — the visual metaphor of pride and violence as clothing: in the ancient world, jewelry and fine garments were signs of wealth and status. The wicked wear pride as their ornament and violence as their robe — their social presentation is made of the very sins that should mark them for judgment. Instead of covenant virtues adorning them, their wickedness has become their badge of honor.</p>",
    "7": "<p>'Their eyes bulge with prosperity; the desires of their heart exceed all bounds' — 'their eyes bulge from fat' is a satirical hyperbole of excessive wealth. In the ancient Near East, visible prosperity (full body, bright eyes, healthy skin) was a recognized sign of well-being. 'The desires of their heart exceed all bounds' — the imagination of the heart overflows; their desires cannot be contained by any moral or social limit.</p>",
    "8": "<p>'They scoff and speak with malice; they talk of oppression with arrogance' — the social dimension of the wicked's prosperity: their speech is scoffing, malicious, and openly oppressive. The combination of prosperity and social dominance: they can say openly what others must whisper, and suffer no consequences. Their impunity in speech reflects their impunity in action.</p>",
    "9": "<p>'They direct their mouths against the heavens, and their tongue ranges across the earth' — the spatial claim of the wicked's speech: from heaven to earth, their tongue sweeps across the entire created order. 'Mouths against the heavens' — speech directed upward as a challenge to divine authority (cf. Rev 13:6: the beast 'opened its mouth to blaspheme God'). The wicked's speech claims universal authority by challenging both the divine sphere (above) and the human sphere (below).</p>",
    "10": "<p>'Therefore people keep returning to them, and a full cup of water is drained by them' — the social magnetism of power: people are attracted to the wicked precisely because of their prosperity and social dominance. The surrounding people empty themselves in service to the powerful. This is the patron-client dynamic at its most exploitative: the powerful attract clients who drain themselves in service, while the powerful accumulate further wealth and status.</p>",
    "11": "<p>'They say, How can God know? Does the Most High have knowledge?' — the practical atheism of the prospering wicked: not denial of divine existence but denial of divine moral attention. If YHWH does not see or does not care about their conduct, the covenant framework of accountability is null. This is the same challenge as Ps 10:11-13 and Job 22:12-14 (Eliphaz's accusation that Job assumed God could not see through the clouds). The question is theological: does the covenant God actually monitor human conduct and respond to it?</p>",
    "12": "<p>'See — these are the wicked, always at ease, growing in wealth' — the summary of the evidence: the wicked are 'at ease' (shalvei olam, at peace always) and 'growing in wealth.' The psalmist has made an empirical observation that challenges the Deuteronomic theology of covenant consequences. The observation is accurate; the theological problem it raises is genuine. The psalmist does not deny the evidence — he is wrestling with it honestly.</p>",
    "13": "<p>'Surely I have kept my heart clean for nothing, and washed my hands in innocence in vain' — the crisis of covenant meaning: if the wicked prosper without consequence, covenant faithfulness (keeping the heart clean) and ritual purity (washing the hands — the declaration of innocence, as in Ps 26:6; Deut 21:6-7) are pointless. 'For nothing' (riq, in vain/empty) is the wisdom vocabulary of futility (Eccl 1:2: havel havalim, vanity of vanities). The psalmist is applying the vanity verdict specifically to the covenant life of righteousness.</p>",
    "14": "<p>'For all day long I have been afflicted, and punishment comes every morning' — the personal experience that contrasts with the wicked's ease (v. 12: 'always at ease'): the psalmist is 'afflicted' (nagua, stricken — the same word used for leprosy in Lev 13 and for the Suffering Servant in Isa 53:4) 'all day long.' 'Punishment every morning' — while the wicked sleep soundly, each morning brings the psalmist fresh chastisement. The asymmetry is the pastoral and theological crisis.</p>",
    "15": "<p>'If I had said, I will speak this way, I would have betrayed the generation of your children' — the check on apostasy: the psalmist did not speak the crisis aloud because doing so would have 'betrayed' the covenant community. The social responsibility of covenant speech: speaking the crisis theology (righteousness is pointless) publicly would have undermined the faith of those whose covenant trust depended on the community's collective testimony. The psalmist's internal struggle remained private precisely out of covenant loyalty to the community.</p>",
    "16": "<p>'When I tried to make sense of all this, it was a torment before my eyes' — 'I tried to make sense of it' — the rational-theological effort to resolve the theodicy problem through reflection alone. It failed: the attempt produced 'torment' (amal, hard labor/misery) rather than resolution. The theodicy problem is not solvable by intellectual effort alone — the psalmist's wisdom categories cannot absorb the evidence he has observed. This is the limit of human wisdom confronted in Job and here.</p>",
    "17": "<p>'Until I entered the sanctuary of God; then I grasped their end' — the resolution comes in the sanctuary (miqdeshei-el, the holy places of God). Not through additional reasoning but through the experience of the divine presence in worship. The sanctuary context shifts the psalmist's perspective: from the immanent time-frame (present prosperity of the wicked) to the transcendent time-frame (their final destiny). 'I grasped their end' — eschatological perspective on the wicked is only possible from within the space where divine reality is encountered: the temple, the sanctuary, the place of covenant worship.</p>",
    "18": "<p>'Surely you have placed them on slippery ground; you cast them down to desolation' — the divine perspective on the wicked's position: what looks like solid prosperity is actually 'slippery ground' (chalaqot, smooth/slick places). The same word as 'nearly slipped' in v. 2: the psalmist who nearly slipped is actually on firmer ground than the wicked who seem secure. The wicked's ease is not a stable platform but a frictionless surface from which they will suddenly fall.</p>",
    "19": "<p>'How suddenly they are destroyed, completely swept away by terrors!' — 'suddenly' — the speed of divine judgment on the wicked is the shocking reversal of their apparent permanence. 'Completely swept away by terrors' — the terrors that end the wicked are the same 'terrors' of death and judgment that characterized Sheol in ancient Israelite thought (Job 18:11, 14; 24:17: the 'terrors of death').</p>",
    "20": "<p>'Like a dream that vanishes when one awakes, so when you arise, O Lord, you despise their fleeting form' — the dream image of the wicked's existence: vivid while it lasts, completely dissolved when morning comes. YHWH's 'arising' is the language of divine judicial intervention after apparent inaction (cf. Ps 44:23: 'Wake up! Why are you sleeping, O Lord?'). When YHWH acts in judgment, the wicked's substantial-seeming prosperity turns out to have been a dream-image with no lasting substance.</p>",
    "21": "<p>'When my heart was embittered and I was pierced in my inner being' — the confession of the emotional and physical experience of the theodicy crisis. 'Embittered' (the verb used for sourdough leavening in Exod 12:19) and 'pierced in my inner being' (my kidneys were sharpened/pierced) — the kidneys/inner being was understood as the seat of deep emotion and conscience (cf. Job 16:13; Ps 16:7; 139:13). The crisis had penetrated to the deepest interior of the psalmist's emotional and moral life.</p>",
    "22": "<p>'I was brutish and ignorant; I was no better than an animal before you' — the psalmist's self-assessment of his condition during the crisis: 'brutish (ba'ar, stupid/animal-like) and ignorant.' The animal comparison (behemot hayiti imach, I was like an animal before you) is the sharpest self-condemnation: the person who reduced the covenant relationship to earthly accounting had descended to the level of creatures who have no covenant knowledge. The sanctuary experience (v. 17) revealed not just the wicked's end but also the psalmist's own blindness.</p>",
    "23": "<p>'Yet I am always with you; you hold me by my right hand' — the pivot from self-condemnation (v. 22) to covenant affirmation. 'Yet I am always with you' — despite the crisis, the confusion, the near-apostasy, the covenant relationship remained intact from YHWH's side. 'You hold me by my right hand' — the guidance image of the stronger leading the weaker: the divine patron grasping the client's hand and preventing the fall that the psalmist described in v. 2. YHWH held him even when the psalmist did not know he was held.</p>",
    "24": "<p>'You guide me with your counsel, and afterward you will receive me into glory' — 'you guide me with your counsel' — divine wisdom as the navigation system through the theodicy crisis; the same counsel the psalmist tried to find through his own reflection (v. 16) is available through covenant relationship. 'Afterward you will receive me into glory' (ve'achar kavod tiqacheni) — one of the most discussed verses in the Psalter: the 'receiving into glory' has been read as a this-worldly vindication, as the moment of death taken by YHWH (cf. Ps 49:15), or as anticipating resurrection. The language closely parallels Gen 5:24 (Enoch: 'God took him') and 2 Kgs 2:10 (Elijah's translation).</p>",
    "25": "<p>'Whom in heaven do I have but you? And on earth there is nothing I desire besides you' — the comprehensive declaration of covenant exclusivity: in heaven and on earth, YHWH alone is desired. The double negation covers the entire cosmos: no heavenly being (no member of the divine council, no angel, no idol) and no earthly thing can substitute for YHWH as the object of desire and trust. This is the Shema's implication worked out psychologically: if YHWH is one, then all other objects of desire are relativized. The psalmist has arrived at the affective dimension of monotheism.</p>",
    "26": "<p>'My flesh and my heart may fail, but God is the strength of my heart and my portion forever' — 'my flesh and my heart may fail' — the physical-emotional exhaustion of the crisis: the complete depletion of natural resources. But YHWH remains 'the strength of my heart (tsur-levavi, the rock of my heart) and my portion (chelqi) forever.' 'My portion' (cheleq) is the inheritance language of the covenant land allotment: YHWH himself is the psalmist's share, as YHWH was the Levites' portion (Num 18:20: 'I am your portion and your inheritance among the Israelites').</p>",
    "27": "<p>'For behold, those who are far from you will perish; you destroy all who are unfaithful to you' — the complement of v. 25's positive declaration: those who are not in the covenant relationship (far from YHWH) perish. Being 'far' is the opposite of 'being near' in v. 28. 'Unfaithful' (zonim, those who commit prostitution/whoredom) — the covenant-betrayal vocabulary of Hosea and Ezekiel: idolatry as sexual unfaithfulness to the covenant spouse. Those who abandon YHWH for other loyalties are destroyed.</p>",
    "28": "<p>'But as for me, it is good to be near God; I have made the Lord GOD my refuge, that I may declare all your works' — the psalm closes with the psalmist's personal covenant declaration, echoing the wisdom principle of Prov 18:10: 'The name of the LORD is a strong tower; the righteous person runs to it and is safe.' 'It is good to be near God' — the summary wisdom of the entire journey: after the theodicy crisis, the sanctuary encounter, and the restored perspective, the simplest and most profound conclusion is that proximity to YHWH is the supreme good. The declaration of YHWH's works continues the mission of testimony that characterized Ps 71's aged psalmist.</p>"
  },
  "74": {
    "1": "<p>Psalm 74 is a national lament over the destruction of the temple — most likely composed in response to the Babylonian destruction of 586 BCE (cf. vv. 3-8: sanctuary defiled and burned, carved paneling smashed, meeting places burned throughout the land). It is attributed to Asaph (or the Asaphite guild) and forms part of the Asaph collection (Ps 73-83). 'O God, why have you rejected us forever? Why does your anger smolder against the sheep of your pasture?' — the central question: divine rejection that appears permanent (lanetsach, forever). The 'sheep of your pasture' is the covenant image of YHWH as shepherd and Israel as his flock (Ps 79:13; 95:7; 100:3) — the flock he now seems to have abandoned to destruction.</p>",
    "2": "<p>'Remember your congregation, which you acquired long ago, the tribe of your inheritance, which you redeemed — Mount Zion, where you dwelt' — 'remember' (zekor) — the covenant appeal to divine memory as the activator of divine action. YHWH's memory of the covenant is the theological engine of Israel's restoration in Exodus (Exod 2:24: 'God remembered his covenant with Abraham'), exile, and return (Lev 26:42, 45). 'Acquired long ago' (qanita qedem) — the Exodus generation as YHWH's purchased people (Exod 15:16). 'Mount Zion, where you dwelt' — YHWH's chosen residence in Zion as the ultimate ground for the petition: restore the place you chose.</p>",
    "3": "<p>'Make your way to the perpetual ruins; the enemy has wrought complete destruction in the sanctuary' — 'perpetual ruins' (mashu'ot netsach, ruins of eternity) — the temple site left as permanent wreckage. YHWH is implored to visit these ruins, to see their condition, to be moved to action. The enemy's 'complete destruction' is laid before YHWH as the evidence demanding his attention. The eyewitness detail of vv. 4-8 provides the specifics of this destruction.</p>",
    "4": "<p>'Your enemies have roared in the midst of your assembly; they have set up their own banners as signs' — the enemy 'roaring' in the place of YHWH's assembly (bemo'adecha, in your meeting-place) is the profanation: the lion's roar in the sanctuary that should have been the place of YHWH's voice. 'Their own banners as signs' — the Babylonian military standards erected in the destroyed sanctuary, replacing the signs of YHWH's presence with the symbols of Babylonian conquest. The sacred space claimed by foreign military insignia is the ultimate desecration.</p>",
    "5": "<p>'They were like men wielding axes to fell a dense forest' — the woodcutting imagery is both literal (they cut the cedar paneling and wood structures of the temple) and metaphorical (the temple as a great forest/garden being clear-cut). The comparison uses the image of the total, systematic destruction of a woodland — nothing is left standing. The temple's cedar panels (1 Kgs 6:9-18: cedar from Lebanon lining the inner sanctuary) made the comparison especially apt.</p>",
    "6": "<p>'All its carved paneling they smashed apart with axes and hammers' — the specific violence against the temple's decoration. The 'carved paneling' (pittuchim) of the temple — the carved cherubim, palm trees, and open flowers that 1 Kgs 6:29-35 describes adorning the inner sanctuary — were systematically destroyed with axes and hammers. The detail of ax-and-hammer destruction gives the eyewitness specificity that marks this as composed by someone who witnessed or had detailed reports of the 586 BCE destruction.</p>",
    "7": "<p>'They set your sanctuary on fire; they defiled the dwelling place of your name by pulling it down to the ground' — the burning of the sanctuary (mishekan shemecha, the dwelling of your name) is the act that extinguished YHWH's official presence in Israel: the divine name's dwelling destroyed. The temple was not merely a building but the place where YHWH's shem (name = his personal presence and authority) was resident (Deut 12:11; 1 Kgs 8:29: 'I have set my name there'). Its destruction left YHWH technically without an earthly residence — a theological crisis without precedent since the original establishment of the tabernacle.</p>",
    "8": "<p>'They said in their hearts, We will crush them all together; they burned down every meeting place of God throughout the land' — the systematic destruction beyond the central sanctuary: the burning of 'all the meeting places of God in the land.' If this refers to pre-exilic synagogue-like gathering places (mo'adei-el), it is the earliest possible reference to local worship assemblies in Israel, suggesting that corporate worship had developed at local sites before the exile, not only in Jerusalem. The total destruction of all worship sites was the comprehensive religious suppression of the Babylonian campaign.</p>",
    "9": "<p>'We see none of our signs; there is no longer a prophet; and none of us knows how long this will last' — the three absences that define the exile's theological crisis: (1) no signs (ototeinu) — no visible tokens of YHWH's presence and action; (2) no prophet — no one speaking YHWH's authoritative word (cf. 1 Sam 3:1: 'The word of the LORD was rare in those days; there was no frequent vision'); (3) no knowledge of duration ('none of us knows how long'). The exile silenced the prophetic voice and removed all signs of divine presence simultaneously — a total communication blackout from YHWH.</p>",
    "10": "<p>'How long, O God, will the enemy mock you? Is the adversary to revile your name forever?' — the ad-matai ('how long?') question that characterizes the lament genre (Ps 13:1-2; 79:5; 80:4; 89:46; Hab 1:2). The lament moves from 'why?' (vv. 1, 11) to 'how long?' — from the question of causation to the question of duration. The enemies' mocking of YHWH and reviling of his name is both an offense against Israel and an offense against YHWH himself — the basis for the petition that YHWH act for his own name's sake.</p>",
    "11": "<p>'Why do you hold back your hand, your right hand? Draw it out from under your garment and act!' — the provocative petition: YHWH's right hand — the divine warrior's instrument of victory — is hidden 'in your bosom' (from within your garment-fold). The image of the concealed weapon: the divine warrior has a powerful hand but has not drawn it. The boldness of the petition (essentially telling YHWH to stop hiding his hand) is characteristic of the lament genre's honesty before the covenant God.</p>",
    "12": "<p>'Yet God my King is from of old, bringing salvation in the midst of the earth' — the pivot from petition to hymnic declaration. 'From of old' (mikedem) — YHWH's ancient track record of salvation: the Exodus, the Conquest, the period of the judges and kings. 'Bringing salvation in the midst of the earth' — YHWH as the active agent of historical rescue. The hymn section (vv. 12-17) recites YHWH's creative and historical acts as the grounds for the petition of vv. 18-23: if he has done these things before, he can act now.</p>",
    "13": "<p>'You split the sea apart by your power; you shattered the heads of the sea monsters on the waters' — the creation/Exodus imagery of YHWH's victory over the primordial waters. 'The sea monsters' (tanninim, sea dragons) represent both the literal sea creatures of chaos and the mythological chaos figures of ANE cosmogony (Babylonian Tiamat, Ugaritic Yam). YHWH's splitting of the sea evokes both the Red Sea crossing (Exod 14:21) and the primordial creation division of the waters (Gen 1:6-7). The Psalm uses creation and Exodus as one theological event: YHWH's mastery over chaos waters.</p>",
    "14": "<p>'You crushed the many heads of Leviathan; you gave his carcass as food for the creatures of the wilderness' — Leviathan was the many-headed sea dragon of Canaanite mythology (the Ugaritic Baal cycle describes Baal killing the seven-headed serpent Lotan/Leviathan). Ps 74:14 appropriates this mythological figure for YHWH's sovereign power: YHWH defeated even the chaos monster that Baal struggled against. 'Giving his carcass as food for wilderness creatures' — the complete desacralization of the chaos monster: far from being the great enemy, Leviathan becomes food for desert animals. The chaos powers are reduced to garbage.</p>",
    "15": "<p>'You split open springs and streams; you dried up the ever-flowing rivers' — the two sides of YHWH's power over water: creating water sources (splitting open springs = the provision in the wilderness, Exod 17:6; Num 20:11) and destroying water sources (drying up rivers = the Jordan crossing, Josh 3:14-17, and the Red Sea crossing). YHWH commands water in both directions: he can produce it from rock and stop it in its course. The same God who controlled the primordial sea (v. 13) controls the terrestrial water systems.</p>",
    "16": "<p>'The day belongs to you; the night also is yours; you established the light and the sun' — the creation hymn continues: YHWH's ownership of time (day and night) as well as space (earth and waters). In the ANE, the sun (Shamash in Babylonia) was a major deity; here the sun is YHWH's creation and instrument. The psalm asserts YHWH's sovereignty over the natural order that other nations attributed to subordinate deities.</p>",
    "17": "<p>'You have fixed all the boundaries of the earth; you have made both summer and winter' — the seasonal order as YHWH's governance: summer and winter are both YHWH's creation, following the covenant promise of Gen 8:22 ('as long as the earth endures, seedtime and harvest, cold and heat, summer and winter, day and night will never cease'). The Psalm has moved from the chaos dragon (vv. 13-14) through the water systems (v. 15) through the luminaries (v. 16) to the seasonal order (v. 17): a comprehensive survey of creation's order under YHWH's sovereignty.</p>",
    "18": "<p>'Remember this, O LORD: the enemy has mocked, and a foolish people has reviled your name' — the petition section resumes with 'remember' (zekor-zot) — the second covenant-memory appeal (cf. v. 2: 'remember your congregation'). The 'foolish people' (am naval) who reviles YHWH's name echoes Deut 32:21 where naval describes those without understanding. YHWH's own covenant song uses naval of Israel in rebellion; here it is applied to the enemy nations who mock YHWH.</p>",
    "19": "<p>'Do not hand over your dove to the pack of enemies; do not forget the community of your poor forever' — 'your dove' (toratech, your turtledove) is an unusual metaphor for Israel: the vulnerable, gentle creature in the grip of predators. The dove as the pure animal of covenant sacrifice (Gen 8:8-12; Lev 1:14; 5:7) evokes Israel's sacrificial role and helplessness. 'The community of your poor' (adat aniyecha) — the covenant community reduced to poverty by the exile and enemy occupation, whom YHWH must not forget.</p>",
    "20": "<p>'Look to your covenant, for the dark corners of the land are filled with dens of violence' — the explicit covenant appeal: look at what was promised, look at what is happening, and act on the contradiction. 'Dark corners (machashakkei-arets, dark places of the land) filled with dens of violence' — the land of Israel's habitations are now places of violent occupation. The covenant land promised as a place of rest and abundance (Deut 12:9-10) is now filled with violence. The appeal to the covenant is the appeal to YHWH's own commitments made under oath.</p>",
    "21": "<p>'Do not let the oppressed be turned away in shame; let the poor and needy praise your name' — the reversal prayer: instead of shame falling on the powerless, let them praise YHWH. The 'oppressed' (dal) and 'poor and needy' (evyon ve'aniy) praise YHWH when they are vindicated — their praise is contingent on YHWH's action. The silence of the poor (shamed) and the mocking of the enemies (vv. 10, 18) would leave YHWH without any worshipers in the land. The petition for the poor's vindication is simultaneously a petition for YHWH's own worship to be restored.</p>",
    "22": "<p>'Rise up, O God, and defend your cause; remember how fools mock you every single day' — 'rise up' (qumah Elohim) — the military call to YHWH to stand up and fight, as in the ancient battle cry of Num 10:35: 'Rise up, O LORD, and may your enemies be scattered.' 'Defend your cause' (rivah rivecha, plead your own case) — YHWH as the plaintiff in his own cause: the enemies' mockery of YHWH is a legal offense against YHWH himself, and YHWH is the one with standing to press charges. The psalm calls YHWH to advocate for his own honor.</p>",
    "23": "<p>'Do not forget the clamor of your enemies; the uproar of those who defy you rises without ceasing' — the closing petition: YHWH must not forget the enemies' persistent noise. 'The uproar of those who defy you rises without ceasing' (sha'on qamecha oleh tamid) — the enemies' defiance is continuous and escalating. Unlike Israel's prayer, which must keep pressing YHWH to remember, the enemies' defiance never stops. The final verse holds both elements: the persistent clamor of the enemy and the implicit plea that YHWH not allow this clamor to go unanswered indefinitely.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'psalms')
    merge_comm(c, PSA_CONTEXT)
    save_comm('mkt-context', 'psalms', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Psalms context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
